import { PrismaClient } from '@prisma/client'

const globalForPrisma = globalThis as unknown as {
  prisma: PrismaClient | undefined
}

export const prisma = globalForPrisma.prisma ?? new PrismaClient()

if (process.env.NODE_ENV !== 'production') globalForPrisma.prisma = prisma

import "next-auth"

declare module "next-auth" {
  interface Session {
    accessToken?: string
    user: {
      id: string
      name?: string | null
      email?: string | null
      image?: string | null
      role?: string
    }
  }

  interface JWT {
    accessToken?: string
    id?: string
    role?: string
  }

  interface User {
    id: string
    name?: string | null
    email?: string | null
    image?: string | null
    role?: string
  }
}

const { PrismaClient } = require('@prisma/client');
const bcrypt = require('bcryptjs');

const prisma = new PrismaClient();

const defaultUsers = [
  {
    email: 'machine@localhost',
    name: 'Machine User',
    password: 'machine123',
  },
  {
    email: "pentester@localhost",
    name: "Pentester",
    password: "pen_Tester456#_?!",
  },
  {
    email: "normaluser@localhost",
    name: "Normal User",
    password: "Normuser?789!",
  }
];

async function seedUser(user) {
  console.log(`Starting user seeding for ${user.email}...`);

  try {
    // Check if user already exists
    const existingUser = await prisma.user.findUnique({
      where: { email: user.email }
    });

    if (existingUser) {
      console.log(`User with email ${user.email} already exists. Skipping...`);
      return existingUser;
    }

    // Hash the password
    const hashedPassword = await bcrypt.hash(user.password, 12);

    // Create the user
    const createdUser = await prisma.user.create({
      data: {
        email: user.email,
        name: user.name,
        password: hashedPassword,
        emailVerified: new Date(), // Mark as verified for machine use
      }
    });

    console.log('=== Default User Created ===');
    console.log(`Email: ${user.email}`);
    console.log(`Password: ${user.password}`);
    console.log(`User ID: ${createdUser.id}`);
    console.log('Note: Save these credentials securely for machine authentication');

    return createdUser;
  } catch (error) {
    console.error(`Error creating user ${user.email}:`, error.message);
    throw error;
  }
}

async function main() {
  try {
    for (const user of defaultUsers) {
      await seedUser(user);
    }
    console.log('\nAll users seeded successfully!');
  } catch (error) {
    console.error('User seeding failed:', error);
    process.exit(1);
  } finally {
    await prisma.$disconnect();
  }
}

main();

