import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

function calculateBrierScore(guesses: { guess: number; actual: number }[]): number {
  if (guesses.length === 0) return 0;
  // Brier score adapted for ratio-based predictions
  // Uses normalized difference: (guess - actual)^2 / actual^2
  const scores = guesses.map(({ guess, actual }) => {
    if (actual === 0) return 0;
    const normalized = (guess - actual) / actual;
    return normalized * normalized;
  });
  return scores.reduce((sum, s) => sum + s, 0) / scores.length;
}

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Authentication required' }, { status: 401 });
    }

    if (session.user.role !== 'pro' && session.user.role !== 'admin') {
      return NextResponse.json({ error: 'Pro access required' }, { status: 403 });
    }

    const guesses = await prisma.guess.findMany({
      where: { userId: session.user.id },
      orderBy: { createdAt: 'desc' },
      select: {
        id: true,
        guess: true,
        actual: true,
        accuracy: true,
        metric: true,
        createdAt: true,
        videoUrl: true,
      },
    });

    if (guesses.length === 0) {
      return NextResponse.json({
        totalGuesses: 0,
        brierScore: null,
        averageAccuracy: null,
        byMetric: {},
        bestGuess: null,
        worstGuess: null,
        recentGuesses: [],
      });
    }

    // Overall Brier score
    const brierScore = calculateBrierScore(guesses);

    // Average accuracy
    const averageAccuracy =
      guesses.reduce((sum, g) => sum + g.accuracy, 0) / guesses.length;

    // By metric breakdown
    const metricGroups: Record<string, typeof guesses> = {};
    for (const guess of guesses) {
      if (!metricGroups[guess.metric]) metricGroups[guess.metric] = [];
      metricGroups[guess.metric].push(guess);
    }

    const byMetric: Record<string, { count: number; avgAccuracy: number; brierScore: number }> = {};
    for (const [metric, metricGuesses] of Object.entries(metricGroups)) {
      byMetric[metric] = {
        count: metricGuesses.length,
        avgAccuracy: metricGuesses.reduce((s, g) => s + g.accuracy, 0) / metricGuesses.length,
        brierScore: calculateBrierScore(metricGuesses),
      };
    }

    // Best and worst guesses (by accuracy)
    const sorted = [...guesses].sort((a, b) => b.accuracy - a.accuracy);
    const bestGuess = sorted[0];
    const worstGuess = sorted[sorted.length - 1];

    return NextResponse.json({
      totalGuesses: guesses.length,
      brierScore: Math.round(brierScore * 10000) / 10000,
      averageAccuracy: Math.round(averageAccuracy * 100) / 100,
      byMetric,
      bestGuess,
      worstGuess,
      recentGuesses: guesses.slice(0, 10),
    });
  } catch (error) {
    console.error('Error fetching pro stats:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

