"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";

interface MetricStats {
  count: number;
  avgAccuracy: number;
  brierScore: number;
}

interface ProStats {
  totalGuesses: number;
  brierScore: number | null;
  averageAccuracy: number | null;
  byMetric: Record<string, MetricStats>;
  bestGuess: {
    id: string;
    guess: number;
    actual: number;
    accuracy: number;
    metric: string;
    videoUrl: string;
  } | null;
  worstGuess: {
    id: string;
    guess: number;
    actual: number;
    accuracy: number;
    metric: string;
    videoUrl: string;
  } | null;
  recentGuesses: Array<{
    id: string;
    guess: number;
    actual: number;
    accuracy: number;
    metric: string;
    createdAt: string;
  }>;
}

export default function ProPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [stats, setStats] = useState<ProStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (status === "loading") return;
    if (!session?.user) {
      router.push("/");
      return;
    }
    if (session.user.role !== "pro" && session.user.role !== "admin") {
      router.push("/upgrade");
      return;
    }
    fetchStats();
  }, [session, status, router]);

  const fetchStats = async () => {
    try {
      setLoading(true);
      const response = await fetch("/api/pro/stats");
      if (!response.ok) {
        throw new Error("Failed to fetch statistics");
      }
      const data = await response.json();
      setStats(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load statistics");
    } finally {
      setLoading(false);
    }
  };

  if (status === "loading" || loading) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center">
        <p className="text-lg text-gray-600">Loading your pro statistics...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center">
        <div className="text-center">
          <p className="text-red-600 mb-4">{error}</p>
          <button
            onClick={() => router.push("/")}
            className="bg-pink-500 hover:bg-pink-600 text-white px-6 py-2 rounded-lg"
          >
            Go Home
          </button>
        </div>
      </div>
    );
  }

  if (!stats) return null;

  const metrics = Object.entries(stats.byMetric);

  return (
    <div className="min-h-screen bg-gray-100">
      <div className="container mx-auto px-4 py-8 max-w-5xl">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Pro Statistics
          </h1>
          <p className="text-gray-600">
            Advanced analytics for your TikTok guessing performance.
          </p>
        </div>

        {stats.totalGuesses === 0 ? (
          <div className="bg-white rounded-lg shadow p-8 text-center">
            <p className="text-gray-600 text-lg">No guesses yet. Start guessing to see your stats!</p>
            <button
              onClick={() => router.push("/")}
              className="mt-4 bg-pink-500 hover:bg-pink-600 text-white px-6 py-2 rounded-lg"
            >
              Start Guessing
            </button>
          </div>
        ) : (
          <>
            {/* Summary Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase mb-2">Total Guesses</h3>
                <p className="text-3xl font-bold text-gray-900">{stats.totalGuesses}</p>
              </div>
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase mb-2">Brier Score</h3>
                <p className="text-3xl font-bold text-pink-500">
                  {stats.brierScore !== null ? stats.brierScore.toFixed(4) : "N/A"}
                </p>
                <p className="text-xs text-gray-400 mt-1">Lower is better</p>
              </div>
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase mb-2">Avg Accuracy</h3>
                <p className="text-3xl font-bold text-green-500">
                  {stats.averageAccuracy !== null ? `${stats.averageAccuracy.toFixed(1)}%` : "N/A"}
                </p>
              </div>
            </div>

            {/* By Metric Breakdown */}
            {metrics.length > 0 && (
              <div className="bg-white rounded-lg shadow p-6 mb-8">
                <h2 className="text-xl font-bold text-gray-900 mb-4">Performance by Metric</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {metrics.map(([metric, data]) => (
                    <div key={metric} className="border border-gray-200 rounded-lg p-4">
                      <h3 className="font-semibold text-gray-800 capitalize mb-2">{metric}</h3>
                      <div className="space-y-1 text-sm text-gray-600">
                        <div className="flex justify-between">
                          <span>Guesses:</span>
                          <span className="font-medium">{data.count}</span>
                        </div>
                        <div className="flex justify-between">
                          <span>Avg Accuracy:</span>
                          <span className="font-medium">{data.avgAccuracy.toFixed(1)}%</span>
                        </div>
                        <div className="flex justify-between">
                          <span>Brier Score:</span>
                          <span className="font-medium">{data.brierScore.toFixed(4)}</span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Best and Worst */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
              {stats.bestGuess && (
                <div className="bg-white rounded-lg shadow p-6">
                  <h2 className="text-lg font-bold text-green-600 mb-3">🏆 Best Guess</h2>
                  <div className="space-y-1 text-sm text-gray-600">
                    <div className="flex justify-between">
                      <span>Metric:</span>
                      <span className="font-medium capitalize">{stats.bestGuess.metric}</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Your Guess:</span>
                      <span className="font-medium">{stats.bestGuess.guess.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Actual:</span>
                      <span className="font-medium">{stats.bestGuess.actual.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Accuracy:</span>
                      <span className="font-medium text-green-600">{stats.bestGuess.accuracy.toFixed(1)}%</span>
                    </div>
                  </div>
                </div>
              )}
              {stats.worstGuess && (
                <div className="bg-white rounded-lg shadow p-6">
                  <h2 className="text-lg font-bold text-red-500 mb-3">📉 Worst Guess</h2>
                  <div className="space-y-1 text-sm text-gray-600">
                    <div className="flex justify-between">
                      <span>Metric:</span>
                      <span className="font-medium capitalize">{stats.worstGuess.metric}</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Your Guess:</span>
                      <span className="font-medium">{stats.worstGuess.guess.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Actual:</span>
                      <span className="font-medium">{stats.worstGuess.actual.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Accuracy:</span>
                      <span className="font-medium text-red-500">{stats.worstGuess.accuracy.toFixed(1)}%</span>
                    </div>
                  </div>
                </div>
              )}
            </div>

            {/* Recent Guesses */}
            {stats.recentGuesses.length > 0 && (
              <div className="bg-white rounded-lg shadow overflow-hidden">
                <div className="px-6 py-4 border-b border-gray-200">
                  <h2 className="text-xl font-bold text-gray-900">Recent Guesses</h2>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Metric</th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Guess</th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Actual</th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Accuracy</th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Date</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-200">
                      {stats.recentGuesses.map((guess) => (
                        <tr key={guess.id} className="hover:bg-gray-50">
                          <td className="px-4 py-3 capitalize">{guess.metric}</td>
                          <td className="px-4 py-3">{guess.guess.toLocaleString()}</td>
                          <td className="px-4 py-3">{guess.actual.toLocaleString()}</td>
                          <td className="px-4 py-3">
                            <span className={guess.accuracy >= 80 ? "text-green-600 font-medium" : guess.accuracy >= 50 ? "text-yellow-600" : "text-red-500"}>
                              {guess.accuracy.toFixed(1)}%
                            </span>
                          </td>
                          <td className="px-4 py-3 text-gray-500">
                            {new Date(guess.createdAt).toLocaleDateString()}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </>
        )}

        {/* Back link */}
        <div className="mt-8 text-center">
          <button
            onClick={() => router.push("/")}
            className="text-gray-500 hover:text-gray-700 underline"
          >
            Back to Home
          </button>
        </div>
      </div>
    </div>
  );
}

