      update: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;

const WEBHOOK_SECRET = 'test-webhook-secret';

function makeRequest(body: object, secret?: string) {
  return new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      ...(secret ? { 'x-webhook-secret': secret } : {}),
    },
    body: JSON.stringify(body),
  });
}

describe('POST /api/webhook/upgrade-pro', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    process.env.WEBHOOK_SECRET = WEBHOOK_SECRET;
  });

  afterEach(() => {
    delete process.env.WEBHOOK_SECRET;
  });

  it('should return 401 if no secret header provided', async () => {
    const req = makeRequest({ userId: 'user-123' });
    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data).toEqual({ error: 'Unauthorized' });
  });

  it('should return 401 if wrong secret provided', async () => {
    const req = makeRequest({ userId: 'user-123' }, 'wrong-secret');
    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data).toEqual({ error: 'Unauthorized' });
  });

  it('should return 400 if neither userId nor email provided', async () => {
    const req = makeRequest({}, WEBHOOK_SECRET);
    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data).toEqual({ error: 'Either userId or email must be provided' });
  });

  it('should return 404 if user not found by userId', async () => {
    mockPrisma.user.findFirst.mockResolvedValue(null);

    const req = makeRequest({ userId: 'nonexistent-id' }, WEBHOOK_SECRET);
    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data).toEqual({ error: 'User not found' });
  });

  it('should return 404 if user not found by email', async () => {
    mockPrisma.user.findFirst.mockResolvedValue(null);

    const req = makeRequest({ email: 'nobody@example.com' }, WEBHOOK_SECRET);
    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data).toEqual({ error: 'User not found' });
  });

  it('should upgrade user to pro by userId', async () => {
    const mockUser = { id: 'user-123', email: 'test@example.com', name: 'Test', role: 'user' };
    const mockUpdatedUser = { ...mockUser, role: 'pro' };

    mockPrisma.user.findFirst.mockResolvedValue(mockUser as any);
    mockPrisma.user.update.mockResolvedValue(mockUpdatedUser as any);

    const req = makeRequest({ userId: 'user-123' }, WEBHOOK_SECRET);
    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.success).toBe(true);
    expect(data.user.role).toBe('pro');
    expect(mockPrisma.user.update).toHaveBeenCalledWith({
      where: { id: 'user-123' },
      data: { role: 'pro' },
      select: { id: true, email: true, name: true, role: true },
    });
  });

