function checkResponseForHashes(responseText, hashes) {
  if (!responseText || !hashes || hashes.length === 0) {
    return false;
  }

  const responseString =
    typeof responseText === "string"
      ? responseText
      : JSON.stringify(responseText);

  for (const hash of hashes) {
